INSERT OR IGNORE INTO chapter (id,tier,chapter_no,title,description,`order`,status,createdAt,updatedAt) VALUES ('23-strategy-os',3,23,'STRATEGY OS','He dieu hanh chien luoc',23,'draft','2026-06-20T15:42:07Z','2026-06-20T15:42:07Z');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('163929a1-366e-48f8-bdf7-34385245b712','23-strategy-os',NULL,2,'23.1 Sáu mục tiêu cốt lõi của Strategy OS','231-sau-muc-tieu-cot-loi-cua-strategy-os',0,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9c91b034-c7de-49c9-9e1d-ca3567df1ec2','163929a1-366e-48f8-bdf7-34385245b712',0,'text','Trong cấu trúc tổng thể của hệ điều hành **Dental Empire OS**, **Strategy OS** đóng vai trò là bộ não chỉ huy tối cao, định hình toàn bộ huyết mạch vận hành của phòng khám RHM. Các phân hệ còn lại như *Marketing OS*, *Sales OS* hay *Clinic OS* suy cho cùng chỉ là những công cụ thực thi đắc lực. Nếu chiến lược thượng tầng bị định vị sai lệch, phòng khám của bạn sẽ rơi vào cái bẫy "tối ưu hóa sai hướng" - tức là đội ngũ của bạn càng nỗ lực làm việc, phòng khám càng nhanh chóng tiến gần đến bờ vực khủng hoảng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('aff72aad-a8ff-470a-a49b-13a93fe5d169','163929a1-366e-48f8-bdf7-34385245b712',1,'text','Bạn cùng ban điều hành khóa chặt tầm nhìn dài hạn, lựa chọn chính xác phân khúc khách hàng và thiết lập các mục tiêu tăng trưởng có tính thực chiến cao theo từng giai đoạn phát triển.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('bad71caa-27fa-40ca-a3b9-72e00e1c700e','163929a1-366e-48f8-bdf7-34385245b712',2,'text','Hệ điều hành chiến lược được thiết kế để giải quyết triệt để 6 bài toán quản trị vĩ mô sau:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('63b81656-c583-4399-8806-256e7a635bed','163929a1-366e-48f8-bdf7-34385245b712',3,'text','- **Định hình bản sắc thương hiệu:** Xác lập rõ nét định vị độc bản của phòng khám, giúp thương hiệu nổi bật hoàn toàn giữa thị trường nha khoa cạnh tranh khốc liệt.- **Lựa chọn dịch vụ mũi nhọn:** Xác định rõ đâu là dòng dịch vụ chủ lực tạo biên lợi nhuận cao (Vũ khí can thiệp sâu như Implant, Chỉnh nha) để tập trung tối đa nguồn lực đầu tư.- **Điêu khắc chân dung khách hàng:** Nhận diện chính xác tệp khách hàng mục tiêu lý tưởng (Customer Avatar) dựa trên hành vi, nỗi đau thực tế và năng lực chi trả tài chính.- **Thiết lập ma trận mục tiêu:** Cấu trúc minh bạch các chỉ số đích về Doanh thu, Lợi nhuận thuần, Số lượng bệnh nhân mới, tỷ lệ Tái khám (Retention) và tỷ lệ Giới thiệu (Referral).- **Quản trị mục tiêu bằng OKRs:** Đóng gói mục tiêu năm thành các mục tiêu và kết quả cốt lõi (OKRs) theo từng quý để toàn bộ bộ máy nhân sự dễ dàng bám sát thực thi.- **Hoạch định ưu tiên vận hành:** Đưa ra bảng ma trận ưu tiên phân bổ ngân sách và nguồn lực con người phù hợp với độ trưởng thành của phòng khám trong từng chặng đường.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('60799603-8f7d-4f8f-80a7-de0eabb41f10','23-strategy-os',NULL,2,'23.2 Phạm vi quản trị toàn diện','232-pham-vi-quan-tri-toan-dien',1,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f0b72845-e901-4e4d-a87b-ecad44e7ab6a','60799603-8f7d-4f8f-80a7-de0eabb41f10',4,'text','Strategy OS chịu trách nhiệm kiểm soát toàn bộ các tài sản chiến lược mang tính sống còn của doanh nghiệp nha khoa, bao gồm:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9b781110-7015-44eb-afa7-16dcf192cf61','60799603-8f7d-4f8f-80a7-de0eabb41f10',5,'image',NULL,'book/23-strategy-os/82a513ca-bcc9-4f07-b432-42db74b1eedc-img01.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('7585b4f9-6105-451d-986c-f5a40b33fd3f','23-strategy-os',NULL,2,'23.3 Quy trình lõi 8 bước vận hành chiến lược toàn diện','233-quy-trinh-loi-8-buoc-van-hanh-chien-luoc-toan-dien',2,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b6689a99-e0b1-4cf8-a41a-71efbb08fdb8','7585b4f9-6105-451d-986c-f5a40b33fd3f',6,'image',NULL,'book/23-strategy-os/ccf39501-5baa-4c98-93e8-341c58707cf7-img02.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f3a42c57-03aa-45a2-a987-713164f9836c','7585b4f9-6105-451d-986c-f5a40b33fd3f',7,'text','Mạch lệnh chiến lược không được đưa ra dựa trên cảm tính của người sáng lập, mà phải tuân thủ nghiêm ngặt quy trình dòng chảy dữ liệu **8 bước** dưới đây:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('61709b97-8fee-4e62-85b9-ca426d8a5737','23-strategy-os','7585b4f9-6105-451d-986c-f5a40b33fd3f',3,'Bước 1 - Market Context Analysis:','buoc-1-market-context-analysis',3,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ce6ddb42-4f5b-4613-88d3-50336f600953','61709b97-8fee-4e62-85b9-ca426d8a5737',8,'text','Nghiên cứu bối cảnh thị trường, phân tích hành vi đối thủ cạnh tranh và xác định các khoảng trống nhu cầu y khoa chưa được đáp ứng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('c4952c15-801f-4787-adbe-df1deeaa1eeb','23-strategy-os','7585b4f9-6105-451d-986c-f5a40b33fd3f',3,'Bước 2 - Brand Positioning:','buoc-2-brand-positioning',4,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('11f5d262-d153-47be-8784-509829ef31f9','c4952c15-801f-4787-adbe-df1deeaa1eeb',9,'text','Xác lập tuyên bố định vị thương hiệu cốt lõi, chọn lựa góc nhìn chuyên môn độc bản để mỏ neo lòng tin vào tâm trí khách hàng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('8b8cf4f9-ba78-48b7-9596-0517ce6727bf','23-strategy-os','7585b4f9-6105-451d-986c-f5a40b33fd3f',3,'Bước 3 - Core Service Selection:','buoc-3-core-service-selection',5,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('49e747e4-f6d0-4137-b7c2-3eaaf12ffb19','8b8cf4f9-ba78-48b7-9596-0517ce6727bf',10,'text','Lựa chọn danh mục dịch vụ mũi nhọn để tập trung nguồn lực quảng cáo, trang thiết bị công nghệ cao và năng lực lâm sàng của Bác sĩ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('d6a7a84b-b879-4902-b1b6-9afcd4d46b8d','23-strategy-os','7585b4f9-6105-451d-986c-f5a40b33fd3f',3,'Bước 4 - Customer Avatar Blueprint:','buoc-4-customer-avatar-blueprint',6,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6bba9824-1a9c-4c40-85a9-1478eaaa9673','d6a7a84b-b879-4902-b1b6-9afcd4d46b8d',11,'text','Xây dựng hồ sơ chi tiết về bệnh nhân mục tiêu: Nỗi sợ hãi sinh học là gì? Kỳ vọng thẩm mỹ ra sao? Rào cản tài chính nằm ở đâu?',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('cc1071c7-b6d7-4625-b6c2-d27e42929c0b','23-strategy-os','7585b4f9-6105-451d-986c-f5a40b33fd3f',3,'Bước 5 - Growth Goal Formatting:','buoc-5-growth-goal-formatting',7,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('81f85365-f3fb-418f-bbe4-de3540be055b','cc1071c7-b6d7-4625-b6c2-d27e42929c0b',12,'text','Thiết lập các chỉ số tài chính vĩ mô và chỉ số sức khỏe hệ thống (Doanh thu ròng, biên lợi nhuận thuần, dòng tiền mặt trả trước).',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('0c6eb946-7cfe-48af-80e3-ef28eac601b5','23-strategy-os','7585b4f9-6105-451d-986c-f5a40b33fd3f',3,'Bước 6 - Quarterly OKR Cascading:','buoc-6-quarterly-okr-cascading',8,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('71abc7b7-db04-439d-a92e-1ccb245ca677','0c6eb946-7cfe-48af-80e3-ef28eac601b5',13,'text','Bẻ gãy mục tiêu tăng trưởng năm thành bảng mục tiêu OKRs chi tiết cho từng quý, phân rã chỉ tiêu xuống các phân hệ OS cấp dưới.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('1d706ee4-76c0-4682-86c2-a72103fc8d5f','23-strategy-os','7585b4f9-6105-451d-986c-f5a40b33fd3f',3,'Bước 7 - OS Priority Planning:','buoc-7-os-priority-planning',9,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('dafcb63c-97de-4d5e-af75-90afa704cd0e','1d706ee4-76c0-4682-86c2-a72103fc8d5f',14,'text','Lập bản kế hoạch ưu hành vận hành: Chỉ định rõ trong quý này phân hệ nào (Ví dụ: Marketing OS hay People OS) cần được tập trung nâng cấp.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('2b792913-bebf-4a7f-afc9-fcd1cf7cd6bf','23-strategy-os','7585b4f9-6105-451d-986c-f5a40b33fd3f',3,'Bước 8 - Monthly Strategy Review:','buoc-8-monthly-strategy-review',10,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('89926ece-9bce-4c89-be8a-52185e0c070e','2b792913-bebf-4a7f-afc9-fcd1cf7cd6bf',15,'text','Tổ chức cuộc họp hội đồng chiến lược định kỳ hằng tháng để đối soát dữ liệu thực tế với OKRs, tiến hành căn chỉnh bánh đà kịp thời.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('61dfb5fb-87d3-4b5a-8845-0a2414f26757','23-strategy-os',NULL,2,'23.4 Đội ngũ phụ trách và ma trận phân quyền','234-oi-ngu-phu-trach-va-ma-tran-phan-quyen',11,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('21eed773-490c-4d1a-9cd1-685f70d6689a','61dfb5fb-87d3-4b5a-8845-0a2414f26757',16,'text','- **Nhân sự chịu trách nhiệm chính (Owner):** Founder / CEO / Chủ phòng khám. Đây là người nắm giữ quyền quyết định tối cao và phê duyệt mọi văn bản chiến lược.- **Nhân sự phối hợp thực thi (Contributors):** Quản lý phòng khám (Clinic Manager), Trưởng phòng Tiếp thị (Marketing Lead), Kế toán trưởng (Finance Lead), và Chuyên viên phân tích dữ liệu (Data Lead). Khối nhân sự này chịu trách nhiệm cung cấp dữ liệu thực địa và thực thi các mục tiêu OKRs được phân rã.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('aee3eccd-cb63-48ad-98cf-b5ea79ef54b4','23-strategy-os',NULL,2,'23.5 Bộ chỉ số KPI chính đo lường hiệu suất chiến lược','235-bo-chi-so-kpi-chinh-o-luong-hieu-suat-chien-luoc',12,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c59dd175-2539-476a-921b-5eff9966d9cb','aee3eccd-cb63-48ad-98cf-b5ea79ef54b4',17,'text','Dashboard quản trị của Strategy OS tập trung kiểm soát các chỉ số sức khỏe vĩ mô mang tính định hướng dòng tiền cho toàn bộ doanh nghiệp:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6239e64b-9ba3-440b-a7e9-c5f575b8ec0d','aee3eccd-cb63-48ad-98cf-b5ea79ef54b4',18,'image',NULL,'book/23-strategy-os/faad1a37-781f-41e3-8e21-25cc7d7f2254-img03.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('19fc16f4-8a7b-414a-8ebe-4d831413d3f2','23-strategy-os',NULL,2,'23.6 Bộ đầu ra tài liệu tiêu chuẩn (Deliverables Bundle)','236-bo-au-ra-tai-lieu-tieu-chuan-deliverables-bundle',13,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('fb1264ed-4520-4c02-aa03-d6c4e1f53015','19fc16f4-8a7b-414a-8ebe-4d831413d3f2',19,'text','Để cấu phần Strategy OS được nghiệm thu hoàn tất và lưu trữ thành tài sản mã nguồn vận hành của nha khoa **Thích Làm Răng**, ban điều hành bắt buộc phải hoàn thiện bộ 7 tài liệu kỹ thuật sau:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('377f32dc-51ad-49c2-a73d-450605df993b','19fc16f4-8a7b-414a-8ebe-4d831413d3f2',20,'text','- **Brand Strategy Sheet:** Bản định vị thương hiệu tổng thể, cấu trúc văn hóa doanh nghiệp và triết lý y đức hệ thống.- **Positioning Statement Document:** Văn bản tuyên bố định vị độc bản ngắn gọn, xác lập ranh giới cạnh tranh chuyên môn với đối thủ.- **Customer Avatar Sheet:** File Master mô tả chi tiết đặc điểm hành vi, tâm lý, nỗi đau và phân khúc thu nhập của tệp khách hàng lý tưởng.- **Core Service Map:** Sơ đồ kiến trúc phễu dịch vụ (Dịch vụ thu hút, Dịch vụ chủ lực can thiệp sâu, Dịch vụ phụ trợ nâng cao).- **Quarterly OKR Sheet:** Bảng mục tiêu và kết quả cốt lõi được số hóa, gán rõ trách nhiệm và chỉ số định lượng cho từng phòng ban hằng quý.- **Annual Growth Plan:** Bản kế hoạch tăng trưởng doanh thu, ngân sách dự phòng và lộ trình mở rộng quy mô hạ tầng vật lý trọn năm.- **Monthly Strategy Review Template:** Biểu mẫu cấu trúc cuộc họp đối soát chiến lược hằng tháng dành cho ban giám đốc.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9fb1ce47-8863-4564-a71c-fd0f525617a8','19fc16f4-8a7b-414a-8ebe-4d831413d3f2',21,'text','**Mantra tối thượng của Strategy OS:***"Chiến lược sai thì mọi nỗ lực thực thi đều là vô ích. Hãy dành thời gian mài sắc lưỡi rìu chiến lược thượng tầng trước khi bắt tay vào chặt cây vận hành. Một nhà quản trị nha khoa thông thái dẫn dắt phòng khám bằng tầm nhìn định vị, chứ không chạy theo dòng khách vãng lai chộp giật của thị trường."*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('fad84949-c8eb-4d94-b0f9-e02254f8699d','23-strategy-os',NULL,2,'BRAND STRATEGY SHEET: [TÊN THƯƠNG HIỆU]','brand-strategy-sheet-ten-thuong-hieu',14,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9ce91838-3991-4e10-8124-fe9084a3f110','fad84949-c8eb-4d94-b0f9-e02254f8699d',22,'text','**Mục tiêu độc giả:** Tài liệu này là "kim chỉ nam" cho toàn bộ đội ngũ (từ Ban điều hành, Marketing đến Nhân sự) nhằm đảm bảo mọi điểm chạm của thương hiệu luôn nhất quán về giá trị, hình ảnh và thông điệp.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('b20e671c-dbbb-41fc-ba38-6684c023f33b','23-strategy-os','fad84949-c8eb-4d94-b0f9-e02254f8699d',3,'NỀN TẢNG CỐT LÕI (BRAND CORE)','nen-tang-cot-loi-brand-core',15,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ea04614d-ced6-40a5-a516-3322bbd3581d','b20e671c-dbbb-41fc-ba38-6684c023f33b',23,'text','*Phần này trả lời cho câu hỏi: Tại sao thương hiệu này tồn tại và thế giới sẽ mất đi điều gì nếu chúng ta biến mất?*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('781b604e-03b1-4b1a-bb25-d0b7372eef69','23-strategy-os','fad84949-c8eb-4d94-b0f9-e02254f8699d',3,'CHÂN DUNG KHÁCH HÀNG &amp; THỊ TRƯỜNG (AUDIENCE &amp; MARKET)','chan-dung-khach-hang-amp-thi-truong-audience-amp-market',16,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b0c18005-e1bf-472e-a7a7-671316b8cef9','781b604e-03b1-4b1a-bb25-d0b7372eef69',24,'text','*Hiểu rõ chúng ta đang phục vụ ai và đang chiến đấu với ai trên "sân chơi".*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('4300d2a7-27a0-4f77-a0bf-a4e4ecd2fa47','23-strategy-os','781b604e-03b1-4b1a-bb25-d0b7372eef69',4,'Khách hàng mục tiêu (Target Audience)','khach-hang-muc-tieu-target-audience',17,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('81144466-bbeb-446e-a32a-51fbbec4497e','4300d2a7-27a0-4f77-a0bf-a4e4ecd2fa47',25,'text','- **Nhân khẩu học:** [Độ tuổi, giới tính, khu vực địa lý, thu nhập, nghề nghiệp phổ biến]- **Điểm đau (Pain Points):** [Họ đang sợ hãi điều gì? Rắc rối họ gặp phải với các giải pháp hiện tại là gì? (Ví dụ: Sợ đau, sợ bị vẽ bệnh, sợ tốn thời gian...)]- **Nhận thức mong muốn (Desired Mindset):** [Họ muốn cảm thấy thế nào sau khi dùng dịch vụ/sản phẩm? (Ví dụ: Yên tâm, tự hào, xứng đáng tiền bạc...)]',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('c243f193-f877-46b9-b799-6014d2b3a520','23-strategy-os','781b604e-03b1-4b1a-bb25-d0b7372eef69',4,'Bản đồ cạnh tranh (Competitive Landscape)','ban-o-canh-tranh-competitive-landscape',18,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ed495f57-3d87-4d30-80b7-db45ac722e05','c243f193-f877-46b9-b799-6014d2b3a520',26,'text','- **Đối thủ trực tiếp:** [Tên Đối thủ A, B] \\rightarrow *Điểm yếu của họ mà mình có thể khai thác.*- **Đối thủ gián tiếp:** [Các giải pháp thay thế khác] \\rightarrow *Cách họ đánh lạc hướng khách hàng.*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('93f3d471-b1a6-478a-9300-4f5d80c3a2ec','23-strategy-os','fad84949-c8eb-4d94-b0f9-e02254f8699d',3,'ĐỊNH VỊ THƯƠNG HIỆU (BRAND POSITIONING)','inh-vi-thuong-hieu-brand-positioning',19,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('55bb1767-9432-4dda-9633-f2dbf032361f','93f3d471-b1a6-478a-9300-4f5d80c3a2ec',27,'text','*Điểm khác biệt giúp thương hiệu bóc tách bản thân ra khỏi đám đông.*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('be229642-a02b-4af7-9b24-b4aa265808bd','93f3d471-b1a6-478a-9300-4f5d80c3a2ec',28,'text','- **Thuộc tính độc nhất (Unique Selling Proposition - USP):**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ccdd0a1a-7ec7-41cb-bebf-cee7b71d32aa','93f3d471-b1a6-478a-9300-4f5d80c3a2ec',29,'text','- *Ví dụ: Quy trình chuẩn hóa ứng dụng công nghệ giúp rút ngắn 30% thời gian chờ đợi nhưng vẫn đảm bảo chất lượng cá nhân hóa.*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('de7702c9-b4cc-4f19-bce0-200a46ec1d75','93f3d471-b1a6-478a-9300-4f5d80c3a2ec',30,'text','- **Tuyên ngôn định vị (Positioning Statement):**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ca4896fb-bbe2-451e-b7d6-13e720f37e58','93f3d471-b1a6-478a-9300-4f5d80c3a2ec',31,'text','- Đối với **[Khách hàng mục tiêu]**, **[Tên thương hiệu]** là **[Khái niệm/Ngành hàng]** duy nhất mang lại **[Lợi ích cốt lõi]** bởi vì **[Bằng chứng thuyết phục - Reason to believe]**.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('46a30aa1-39c4-4bdb-bd97-074d784f077f','23-strategy-os','fad84949-c8eb-4d94-b0f9-e02254f8699d',3,'HÌNH MẪU &amp; CÁ TÍNH (BRAND PERSONALITY &amp; VOICE)','hinh-mau-amp-ca-tinh-brand-personality-amp-voice',20,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9f5086b1-7895-4a1f-9d76-0cce9e3169c5','46a30aa1-39c4-4bdb-bd97-074d784f077f',32,'text','*Nếu thương hiệu này là một con người, họ sẽ trông như thế nào và giao tiếp ra sao?*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4c583da7-f84d-4904-8504-0e4e275e2839','46a30aa1-39c4-4bdb-bd97-074d784f077f',33,'text','- **Hình mẫu thương hiệu (Brand Archetype):** [Chọn 1-2 hình mẫu chủ đạo. Ví dụ: *Người Bảo Hộ (Caregiver)* kết hợp *Chuyên Gia (Sage)*].- **Tính cách thương hiệu (Brand Traits):** 3 tính từ đại diện cho thái độ thương hiệu.*Chuyên nghiệp* (Nhưng không xa cách)- *Tử tế* (Nhận trách nhiệm đến cùng)- *Minh bạch* (Rõ ràng trong thông tin và số liệu)',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('9adad8ee-53e8-4a0d-b77f-776f47e511bd','23-strategy-os','46a30aa1-39c4-4bdb-bd97-074d784f077f',4,'Quy chuẩn Giọng điệu (Voice &amp; Tone)','quy-chuan-giong-ieu-voice-amp-tone',21,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('09c8420a-894f-42e8-a28d-a557e6b03325','23-strategy-os','fad84949-c8eb-4d94-b0f9-e02254f8699d',3,'HỆ THỐNG NHẬN DIỆN THƯƠNG HIỆU (BRAND IDENTITY ELEMENTS)','he-thong-nhan-dien-thuong-hieu-brand-identity-elements',22,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5b70092a-52cc-4879-97ae-c8486f16c0e1','09c8420a-894f-42e8-a28d-a557e6b03325',34,'text','*Bộ lọc trực quan hóa chiến lược.*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d55088c8-7e2c-489e-9ecf-1ec638b2ca46','09c8420a-894f-42e8-a28d-a557e6b03325',35,'text','- **Bảng màu chủ đạo (Color Palette):***Màu chính:* [Mã màu Hex] (Thể hiện sự tin cậy, chuyên nghiệp)- *Màu phụ/Nhấn:* [Mã màu Hex] (Tạo điểm nhấn, năng lượng)',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6bbebf4c-8cb2-4038-842a-eae69c0451e3','09c8420a-894f-42e8-a28d-a557e6b03325',36,'text','- *Tiêu đề & Văn bản:* [Ưu tiên các font chữ hiện đại, có độ đọc tốt và bo góc gọn gàng trên cả nền tảng số lẫn in ấn, ví dụ như **Be Vietnam Pro**].',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('42c30995-8787-42e1-ae2c-d4b49293290b','09c8420a-894f-42e8-a28d-a557e6b03325',37,'text','- Ưu tiên hình ảnh thực tế, con người thật, bối cảnh sạch sẽ, ánh sáng tự nhiên. Hạn chế tối đa ảnh stock dàn dựng thiếu tự nhiên.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('38894dab-a3c6-4cf4-b54b-6b72658d8094','23-strategy-os','fad84949-c8eb-4d94-b0f9-e02254f8699d',3,'ĐIỂM CHẠM VÀ HỆ THỐNG ĐO LƯỜNG (TOUCHPOINTS &amp; METRICS)','iem-cham-va-he-thong-o-luong-touchpoints-amp-metrics',23,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('578285e3-40dc-406a-937a-5147cfd11339','23-strategy-os','38894dab-a3c6-4cf4-b54b-6b72658d8094',4,'Các điểm chạm cốt lõi','cac-iem-cham-cot-loi',24,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('93f57426-2953-4a45-a9ea-4e171042e3d4','578285e3-40dc-406a-937a-5147cfd11339',38,'text','- **Digital:** Website, Fanpage, Hệ thống quản trị nội bộ.- **Physical:** Không gian trải nghiệm trực tiếp, bao bì sản phẩm, đồng phục nhân sự.- **Human:** Kịch bản tư vấn của nhân viên, quy trình chăm sóc sau dịch vụ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('43f12c16-d13a-4fed-aa32-5201182d13ff','23-strategy-os','38894dab-a3c6-4cf4-b54b-6b72658d8094',4,'Chỉ số đo lường sức khỏe thương hiệu (Brand Health Metrics)','chi-so-o-luong-suc-khoe-thuong-hieu-brand-health-metrics',25,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5806a902-027a-4791-ab32-f9e72da27c05','43f12c16-d13a-4fed-aa32-5201182d13ff',39,'text','- **Mức độ nhận biết:** Traffic website, lượt tiếp cận tự nhiên (Organic Reach).- **Mức độ trung thành:** Tỷ lệ khách hàng quay lại (Retention Rate), chỉ số giới thiệu khách hàng mới (NPS - Net Promoter Score).- **Sự nhất quán:** Tỷ lệ tuân thủ quy trình checklist của đội ngũ vận hành.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('760bb427-101f-4a4c-a07a-dcb2711d1109','23-strategy-os',NULL,2,'POSITIONING STATEMENT DOCUMENT','positioning-statement-document',26,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ba6621d4-4989-4c0b-93cf-d1d2b40762f0','760bb427-101f-4a4c-a07a-dcb2711d1109',40,'text','**Mục đích:** Tài liệu này định hình vị thế độc nhất của thương hiệu trong tâm trí khách hàng so với đối thủ cạnh tranh. Đây là gốc rễ để đội ngũ Marketing xây dựng thông điệp và đội ngũ Vận hành thiết kế trải nghiệm khách hàng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('92dcc64b-b029-42a9-a577-831d1a23cb6c','23-strategy-os','760bb427-101f-4a4c-a07a-dcb2711d1109',3,'KHUNG TUYÊN NGÔN ĐỊNH VỊ CỐT LÕI (THE CORE FORMULA)','khung-tuyen-ngon-inh-vi-cot-loi-the-core-formula',27,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('bdd93c28-b074-4d78-b754-111d932b81e6','92dcc64b-b029-42a9-a577-831d1a23cb6c',41,'text','Tuyên ngôn định vị của chúng ta được đúc kết theo công thức chuẩn quốc tế:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('277e3f11-d290-4ca1-83a1-48c2c8a91578','92dcc64b-b029-42a9-a577-831d1a23cb6c',42,'text','**Dành cho** `[Khách hàng mục tiêu]`, `[Tên thương hiệu]` **là** `[Khung tham chiếu / Ngành hàng]` **mang lại** `[Điểm khác biệt cốt lõi / USP]` **bởi vì** `[Bằng chứng thuyết phục / Reason to Believe]`.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ee737c65-83f6-4572-802b-c7e315ebdb89','92dcc64b-b029-42a9-a577-831d1a23cb6c',43,'text','*Bản dịch nội bộ trực quan:*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b1ddac7e-97ec-4df9-adc4-9f7118663294','92dcc64b-b029-42a9-a577-831d1a23cb6c',44,'text','- **Chúng ta phục vụ ai:** `[Khách hàng mục tiêu]`- **Chúng ta là ai trong mắt họ:** `[Ngành hàng]`- **Tại sao họ phải chọn chúng ta thay vì đối thủ:** `[USP]`- **Tại sao họ có thể tin chúng ta làm được điều đó:** `[Reason to Believe]`',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('a745fcc8-8206-4dad-a4dd-f5a490bbfbb1','23-strategy-os','760bb427-101f-4a4c-a07a-dcb2711d1109',3,'PHÂN TÍCH CHI TIẾT 4 THÀNH PHẦN CỐT LÕI','phan-tich-chi-tiet-4-thanh-phan-cot-loi',28,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('dd72f987-920d-4d1a-a8bb-e498d651a4db','23-strategy-os','a745fcc8-8206-4dad-a4dd-f5a490bbfbb1',4,'2.1. Khách Hàng Mục Tiêu &amp; Sự Thấu Hiểu Sâu Sắc (Target Audience &amp; Insight)','21-khach-hang-muc-tieu-amp-su-thau-hieu-sau-sac-target-audience-amp-insight',29,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2ca7d619-caa6-4213-ab06-01fc393d9bb3','dd72f987-920d-4d1a-a8bb-e498d651a4db',45,'text','- **Phân khúc cốt lõi:** Những khách hàng coi trọng chất lượng, sự minh bạch và trải nghiệm chuẩn hóa thay vì chỉ quan tâm đến giá rẻ.- **Điểm đau lớn nhất (Core Pain Point):**Sợ bị "vẽ bệnh", chi phí mập mờ, phát sinh trong quá trình sử dụng dịch vụ/sản phẩm.- Sợ mất thời gian chờ đợi do quy trình vận hành lỏng lẻo, thiếu chuyên nghiệp.- Thiếu niềm tin vào các lời quảng cáo thổi phồng trên thị trường.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('f34113ea-53e4-45e8-8e25-dbab0fa4cb41','23-strategy-os','a745fcc8-8206-4dad-a4dd-f5a490bbfbb1',4,'2.2. Khung Tham Chiếu (Frame of Reference / Market Category)','22-khung-tham-chieu-frame-of-reference-market-category',30,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('50779b32-6102-4bac-8190-3dd727bf01f4','f34113ea-53e4-45e8-8e25-dbab0fa4cb41',46,'text','- Thương hiệu định vị mình nằm trong phân khúc: **Dịch vụ/Giải pháp Chuẩn hóa, Minh bạch và Ứng dụng Công nghệ/Hệ thống kiểm soát chất lượng.**- Chúng ta không cạnh tranh về giá thấp nhất; chúng ta cạnh tranh về **hiệu suất vận hành, tính chính xác và trải nghiệm tử tế.**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('7cd8b887-e1b2-40e0-a525-6263fc0447ec','23-strategy-os','a745fcc8-8206-4dad-a4dd-f5a490bbfbb1',4,'2.3. Điểm Khác Biệt Cốt Lõi (Point of Differentiation / USP)','23-iem-khac-biet-cot-loi-point-of-differentiation-usp',31,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('78186682-a5d2-427d-b23c-1be8b73c8e8f','7cd8b887-e1b2-40e0-a525-6263fc0447ec',47,'text','- **Lợi ích chức năng (Functional Benefit):** Quy trình tối ưu giúp rút ngắn thời gian chờ đợi, cam kết chính xác, rõ ràng về lộ trình và chi phí ngay từ đầu.- **Lợi ích cảm xúc (Emotional Benefit):** Mang lại sự **Yên tâm tuyệt đối** và cảm giác **Được tôn trọng** nhờ sự minh bạch trong mọi điểm chạm.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('45983a9c-14ca-40aa-af43-94c721ff6260','23-strategy-os','a745fcc8-8206-4dad-a4dd-f5a490bbfbb1',4,'2.4. Bằng Chứng Thuyết Phục (Reason to Believe - RTB)','24-bang-chung-thuyet-phuc-reason-to-believe-rtb',32,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2fefa2a4-731b-4e21-8418-f448ddd0c2ea','45983a9c-14ca-40aa-af43-94c721ff6260',48,'text','- **Hệ thống & Quy trình:** Áp dụng hệ thống checklist nghiêm ngặt cho từng công đoạn vận hành (không phụ thuộc vào cảm xúc cá nhân của nhân sự).- **Triết lý quản trị chuyên nghiệp:** Quản trị dựa trên kết quả thực tế, năng lực thực chất và đạo đức nghề nghiệp cao.- **Sự minh bạch tuyệt đối:** Mọi thông tin về chi phí, nguồn gốc nguyên vật liệu/công cụ và cam kết bảo hành đều được số hóa và công khai rõ ràng cho khách hàng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('d52f0a69-1b1f-4aa4-b60d-f9f1e07b33b4','23-strategy-os','760bb427-101f-4a4c-a07a-dcb2711d1109',3,'MA TRẬN THÔNG ĐIỆP HỖ TRỢ (SUPPORTING MESSAGING MATRIX)','ma-tran-thong-iep-ho-tro-supporting-messaging-matrix',33,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ecf60deb-6161-46d0-b5c0-b4c365039bc7','d52f0a69-1b1f-4aa4-b60d-f9f1e07b33b4',49,'text','Để chứng minh cho tuyên ngôn định vị, mọi nội dung truyền thông (Bài viết, Video, Website) phải xoay quanh 3 trụ cột thông điệp sau:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('c20a6936-6ac6-431b-b2a8-5c3bdd2c0612','23-strategy-os','760bb427-101f-4a4c-a07a-dcb2711d1109',3,'ĐỒNG BỘ HÓA TRỰC QUAN &amp; HÀNH VI (ALIGNMENT GUILDLINES)','ong-bo-hoa-truc-quan-amp-hanh-vi-alignment-guildlines',34,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('62b803ac-ee9a-44f9-8fd2-dc4f5aef3e04','c20a6936-6ac6-431b-b2a8-5c3bdd2c0612',50,'text','Tuyên ngôn định vị phải được phản ánh đồng điệu qua cả thị giác (Visual) lẫn hành vi (Behavior) của doanh nghiệp:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('dce6377f-c268-4bd8-92f3-ddba66487077','23-strategy-os','c20a6936-6ac6-431b-b2a8-5c3bdd2c0612',4,'Đồng bộ trực quan (Visual Alignment)','ong-bo-truc-quan-visual-alignment',35,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8bfe27e8-a9f4-43b0-88cc-2c129e8802dc','dce6377f-c268-4bd8-92f3-ddba66487077',51,'text','- **Phong cách thiết kế:** Gọn gàng, hiện đại, mang tính cấu trúc vững chãi, tạo cảm giác đáng tin cậy và chuyên nghiệp.- **Hệ Typography (Font chữ):** Để thể hiện tính minh bạch, chính xác và tinh thần tối ưu quy trình bằng hệ thống, ưu tiên sử dụng các font chữ không chân hiện đại, độ đọc tối ưu trên cả nền tảng số và in ấn (Ví dụ tiêu biểu: **Be Vietnam Pro**). Khoảng cách dòng và phân cấp tiêu đề phải rõ ràng, sạch sẽ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('e92ae018-b172-450f-b22e-363ec137b1ac','23-strategy-os','c20a6936-6ac6-431b-b2a8-5c3bdd2c0612',4,'Đồng bộ hành vi (Behavioral Alignment)','ong-bo-hanh-vi-behavioral-alignment',36,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('663cb546-55ca-4128-a054-0ee534ab40af','e92ae018-b172-450f-b22e-363ec137b1ac',52,'text','- Nhân sự tư vấn và vận hành không sử dụng các kịch bản chèo kéo, ép doanh số.- Tất cả nhân viên bắt buộc tuân thủ hệ thống checklist công việc hàng ngày để đảm bảo dịch vụ cung cấp cho mọi khách hàng đều đồng đều về chất lượng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('98dd68aa-b3f1-45d1-9e26-af720b4d99d2','23-strategy-os','760bb427-101f-4a4c-a07a-dcb2711d1109',3,'NGUYÊN TẮC ÁP DỤNG TRONG TRUYỀN THÔNG (DO''S &amp; DON''TS)','nguyen-tac-ap-dung-trong-truyen-thong-dos-amp-donts',37,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ff5e4513-84c1-4648-9329-97d378570381','98dd68aa-b3f1-45d1-9e26-af720b4d99d2',53,'text','- **NÊN (DO):**Luôn nói có sách, mách có chứng (Đưa số liệu cụ thể, quy trình minh bạch, hình ảnh thật của doanh nghiệp thay vì ảnh stock dàn dựng).- Tập trung nhấn mạnh vào "giá trị nhận lại" và "sự an tâm" của khách hàng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4f9f2ea4-2983-48c8-a427-a3ceee7c9d02','98dd68aa-b3f1-45d1-9e26-af720b4d99d2',54,'text','- Sử dụng các từ ngữ sáo rỗng vô căn cứ như "Tốt nhất", "Rẻ nhất", "Hoàn hảo nhất".- Thực hiện các chương trình giảm giá sâu, giật gân làm hạ thấp định vị uy tín và tử tế của thương hiệu.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('68029a47-768c-4deb-b21d-fd079aa6f146','23-strategy-os',NULL,2,'FILE MASTER: CUSTOMER AVATAR SHEET','file-master-customer-avatar-sheet',38,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9ec72544-a725-4a28-8537-defdcf3cfcdb','68029a47-768c-4deb-b21d-fd079aa6f146',55,'text','**Mục đích chiến lược:** Tài liệu Master này phác họa chân dung tệp khách hàng lý tưởng (Ideal Customer Profile - ICP). Định hướng cho toàn bộ chiến dịch marketing, kịch bản tư vấn và quy trình vận hành tại điểm chạm để tối ưu hóa hiệu suất.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('388ebfbe-cd47-4810-b57d-b7e30f1ced5e','23-strategy-os','68029a47-768c-4deb-b21d-fd079aa6f146',3,'','',39,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('91465472-4142-4016-b1e2-93dde3423708','23-strategy-os','68029a47-768c-4deb-b21d-fd079aa6f146',3,'PHÂN KHÚC THU NHẬP &amp; NHÂN KHẨU HỌC (DEMOGRAPHICS &amp; INCOME)','phan-khuc-thu-nhap-amp-nhan-khau-hoc-demographics-amp-income',40,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('bfe89ca2-e7bc-48ee-a76c-3d9fca86ca36','91465472-4142-4016-b1e2-93dde3423708',56,'text','Định vị rõ nhóm khách hàng có giá trị trọn đời (LTV) cao nhất và có khả năng chi trả cho các giải pháp chất lượng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ceb24aba-022c-4d2f-bd0e-c38eca2c3389','91465472-4142-4016-b1e2-93dde3423708',57,'text','- **Phân khúc thu nhập:** Nhóm thu nhập chủ động, ổn định (Phân khúc B và A-segment)(). Họ sẵn sàng chi trả mức giá xứng đáng để đổi lấy sự an tâm và dịch vụ chuẩn hóa, minh bạch thay vì tìm kiếm giải pháp giá rẻ.  - **Độ tuổi chủ đạo:** 25 - 45 tuổi (Giai đoạn chín muồi về sự nghiệp, có ý thức cực kỳ cao về chất lượng cuộc sống, sức khỏe và giá trị thời gian).  - **Nghề nghiệp phổ biến:** Chủ doanh nghiệp vừa và nhỏ, quản lý cấp trung/cao, chuyên gia, freelancer trình độ cao hoặc nhân sự làm việc trong môi trường chuyên nghiệp.  - **Khu vực địa lý:** Tập trung tại các đô thị lớn hoặc khu vực phát triển có lối sống hiện đại, hạ tầng tốt.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('c8d93955-e39f-4857-866d-cb0f6ec65a50','23-strategy-os','68029a47-768c-4deb-b21d-fd079aa6f146',3,'ĐẶC ĐIỂM TÂM LÝ HỌC &amp; HỆ GIÁ TRỊ (PSYCHOGRAPHICS &amp; CORE MINDSET)','ac-iem-tam-ly-hoc-amp-he-gia-tri-psychographics-amp-core-mindset',41,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d023b43b-3d99-4a3e-9f29-4d2a9801cbf1','c8d93955-e39f-4857-866d-cb0f6ec65a50',58,'text','Thấu hiểu thế giới nội tâm để xây dựng thông điệp truyền thông không thể chối từ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('dee15f99-0914-4dad-a4c2-edd10570bbea','c8d93955-e39f-4857-866d-cb0f6ec65a50',59,'text','- **Triết lý sống:** Đề cao hiệu suất, sự gọn gàng và tính hệ thống. Họ yêu thích việc ứng dụng công nghệ để tối ưu hóa trải nghiệm và tiết kiệm thời gian hàng ngày.  - **Hệ giá trị cốt lõi:** Tôn trọng sự tử tế, tính chính xác và sự minh bạch tuyệt đối. Họ dị ứng với các quy trình lỏng lẻo, thông tin mập mờ hoặc chiêu trò quảng cáo thổi phồng.  - **Nhận thức mong muốn (Desired Mindset):** Sau khi sử dụng dịch vụ/sản phẩm, họ muốn cảm thấy an tâm tuyệt đối, tự hào vì sự lựa chọn thông minh và cảm thấy bản thân được tôn trọng một cách chuyên nghiệp.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('103a8e67-bc51-49b0-82aa-3c695dec3062','23-strategy-os','68029a47-768c-4deb-b21d-fd079aa6f146',3,'HÀNH VI &amp; THÓI QUEN TIẾP CẬN (BEHAVIOR &amp; HABITS)','hanh-vi-amp-thoi-quen-tiep-can-behavior-amp-habits',42,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('17581d35-8961-48f5-8902-b9d9ffe481d2','103a8e67-bc51-49b0-82aa-3c695dec3062',60,'text','Biết rõ khách hàng ở đâu và ra quyết định như thế nào để xuất hiện đúng lúc.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a7c25f8c-98ff-4377-96df-d059a42bbb7e','103a8e67-bc51-49b0-82aa-3c695dec3062',61,'text','- **Hành vi tìm kiếm thông tin:** Chủ động tra cứu dữ liệu trước khi mua hàng. Họ có xu hướng đọc bài phân tích sâu, xem video review thực tế, tìm hiểu kỹ về quy trình, công nghệ và uy tín thương hiệu hơn là tin vào các chương trình giảm giá sốc.  - **Hành vi tiêu dùng:** Đòi hỏi trải nghiệm nhất quán từ trực tuyến (Online) đến trực tiếp (Offline). Họ sẵn sàng trung thành với thương hiệu nếu dịch vụ thực tế đáp ứng đúng cam kết truyền thông và vận hành chuẩn hóa.  - **Kênh tiếp cận ưu thích:** Các nền tảng số có tính chia sẻ kiến thức chuyên sâu như Facebook, YouTube, Website chuyên ngành hoặc các cộng đồng chuyên môn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('fb6f1338-0bfb-42a3-976f-607ccac50802','23-strategy-os','68029a47-768c-4deb-b21d-fd079aa6f146',3,'NỖI ĐAU, NỖI SỢ &amp; RÀO CẢN TÂM LÝ (PAIN POINTS &amp; BARRIERS)','noi-au-noi-so-amp-rao-can-tam-ly-pain-points-amp-barriers',43,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('65c843a4-1002-4056-91f7-8a4f3c1f2bbe','fb6f1338-0bfb-42a3-976f-607ccac50802',62,'text','Những "điểm nghẽn" khiến khách hàng do dự. Doanh nghiệp giải quyết được những điều này sẽ chiếm trọn niềm tin.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6198072b-1a3c-4752-9fa6-b6fd6f71a295','fb6f1338-0bfb-42a3-976f-607ccac50802',63,'text','- **Nỗi sợ bị mập mờ, "vẽ bệnh":** Sợ gặp phải các chi phí ẩn, chi phí phát sinh không rõ ràng trong quá trình sử dụng dịch vụ(). Sợ người tư vấn cố tình ép doanh số thay vì đưa ra giải pháp thực chất cho vấn đề của họ().  - **Nỗi đau lãng phí thời gian:** Sợ quy trình vận hành rườm rà, quản lý lỏng lẻo dẫn đến việc phải chờ đợi lâu do sự thiếu chuyên nghiệp của đơn vị cung cấp.  - **Khủng hoảng niềm tin thị trường:** Mất niềm tin vào những lời hứa hẹn sáo rỗng hoặc hình ảnh quảng cáo dàn dựng thiếu tự nhiên. Họ cần những bằng chứng thực tế và xác thực().',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('f75b1029-068c-4e06-88ac-2d3eb726072d','23-strategy-os','68029a47-768c-4deb-b21d-fd079aa6f146',3,'MA TRẬN ĐỒNG BỘ MARKETING &amp; VẬN HÀNH ĐỂ HÓA GIẢI NỖI ĐAU','ma-tran-ong-bo-marketing-amp-van-hanh-e-hoa-giai-noi-au',44,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ea1178e1-263a-4f8c-8bac-367438bed924','f75b1029-068c-4e06-88ac-2d3eb726072d',64,'text','Bảng ma trận chuyển hóa nỗi đau của khách hàng thành hành động cụ thể cho từng bộ phận():',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('0435600e-6922-4805-a059-4551b0c39e02','23-strategy-os',NULL,2,'🗺️ CORE SERVICE MAP (SƠ ĐỒ KIẾN TRÚC PHỄU DỊCH VỤ)','core-service-map-so-o-kien-truc-pheu-dich-vu',45,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('26a75c60-f507-47c0-87c4-8aa92d2f98e4','0435600e-6922-4805-a059-4551b0c39e02',65,'text','**Mục tiêu chiến lược:** Xây dựng một hành trình dịch vụ logic, minh bạch, nơi khách hàng đi từ "thử nghiệm ít rủi ro" đến "can thiệp sâu với niềm tin tuyệt đối" và cuối cùng là "gắn bó dài lâu với hệ sinh thái phụ trợ".',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('ed12a189-42e4-4631-bcb5-10a1fc75b568','23-strategy-os','0435600e-6922-4805-a059-4551b0c39e02',3,'TỒNG QUAN KIẾN TRÚC 3 TẦNG PHỄU','tong-quan-kien-truc-3-tang-pheu',46,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('992c26fc-b0c0-4fb2-80b6-34dabb7094b6','ed12a189-42e4-4631-bcb5-10a1fc75b568',66,'text','```Plain Text
[ TẦNG 1: DỊCH VỤ THU HÚT ]       --> Tạo nhận thức, phá vỡ rào cản hoài nghi (CAC tối ưu)              |              v   [ TẦNG 2: DỊCH VỤ CHỦ LỰC ]       --> Can thiệp sâu, tạo doanh thu & khẳng định chuyên môn              |              v   [ TẦNG 3: DỊCH VỤ PHỤ TRỢ NÂNG CAO ] --> Tăng LTV, cá nhân hóa trải nghiệm & duy trì bền vững
```',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('957fa294-34d0-4ccc-802e-731608f91e6a','23-strategy-os','0435600e-6922-4805-a059-4551b0c39e02',3,'CHI TIẾT 3 TẦNG KIẾN TRÚC DỊCH VỤ','chi-tiet-3-tang-kien-truc-dich-vu',47,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('bafa813f-daff-4436-ac83-8bbbf296e5bf','23-strategy-os','0435600e-6922-4805-a059-4551b0c39e02',3,'🧲 Tầng 1: Dịch vụ Thu hút (Front-End / Hook Service)','tang-1-dich-vu-thu-hut-front-end-hook-service',48,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('fef27cf5-85f2-4a5a-b8d2-a0678bfd17e3','bafa813f-daff-4436-ac83-8bbbf296e5bf',67,'text','*Phá vỡ sự hoài nghi của thị trường bằng một trải nghiệm "rủi ro bằng 0" nhưng tiêu chuẩn vận hành ở mức tối đa.*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b13663ed-ef41-468d-95e2-ba88011a540b','bafa813f-daff-4436-ac83-8bbbf296e5bf',68,'text','- **Mục tiêu cốt lõi:** Thu hút lượng lớn khách hàng tiềm năng thuộc tệp lý tưởng, số hóa thông tin khách hàng vào CRM và thiết lập niềm tin ban đầu.- **Đặc điểm vận hành:**Thời gian thực hiện nhanh, quy trình chuẩn hóa cao, nhân sự dễ dàng thực thi theo checklist.- Giá thành thấp (hoặc miễn phí có điều kiện) nhưng **tuyệt đối không hạ thấp chất lượng**. Chất lượng tầng này quyết định tỷ lệ chuyển đổi sang tầng sau.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a64e03e7-d94c-43f1-8f4c-c93a600fa34c','bafa813f-daff-4436-ac83-8bbbf296e5bf',69,'text','- *Mô hình Dịch vụ/Phòng khám:* Thăm khám tổng quát, chụp phim tầm soát công nghệ cao, vệ sinh/chăm sóc cơ bản miễn phí hoặc chi phí trải nghiệm.- *Mô hình Kỹ thuật/Bán lẻ:* Khóa hướng dẫn chuyên sâu ngắn hạn, gói bảo dưỡng thiết bị định kỳ, bộ công cụ chẩn đoán lỗi hệ thống.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('b2caabd2-808b-4897-b983-5e600baa0461','23-strategy-os','0435600e-6922-4805-a059-4551b0c39e02',3,'🎯 Tầng 2: Dịch vụ Chủ lực Can thiệp sâu (Core Service)','tang-2-dich-vu-chu-luc-can-thiep-sau-core-service',49,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c8b2e175-7372-405c-ad21-b3ed11b1e2d3','b2caabd2-808b-4897-b983-5e600baa0461',70,'text','*Trọng tâm tạo ra doanh số lớn và khẳng định vị thế thương hiệu tử tế, chuyên môn cao trên thị trường.*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6479a009-6645-4043-bcb2-02ced09b5be6','b2caabd2-808b-4897-b983-5e600baa0461',71,'text','- **Mục tiêu cốt lõi:** Giải quyết triệt để nỗi đau/vấn đề lớn nhất của khách hàng. Đây là nguồn doanh thu và lợi nhuận chính của doanh nghiệp.- **Đặc điểm vận hành:**Đòi hỏi trình độ chuyên môn cao hoặc giải pháp công nghệ toàn diện.- Quy trình can thiệp sâu, lộ trình rõ ràng, cam kết bằng văn bản hoặc hợp đồng minh bạch, không phát sinh chi phí ẩn.- Đo lường kết quả thực tế (Results) một cách nghiêm ngặt.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d9d04355-dedb-441d-ba58-900ffdb14e96','b2caabd2-808b-4897-b983-5e600baa0461',72,'text','- *Mô hình Dịch vụ/Phòng khám:* Các gói điều trị chuyên sâu, phục hình, can thiệp thẩm mỹ hoặc giải pháp chỉnh nha toàn diện có lộ trình số hóa.- *Mô hình Kỹ thuật/Bán lẻ:* Cung cấp hệ thống máy móc giải pháp lớn, gói thi công/lắp đặt hạ tầng đồng bộ cho nhà xưởng/phòng khám.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('495de6a1-1b5d-4bf5-bd09-07523091fc68','23-strategy-os','0435600e-6922-4805-a059-4551b0c39e02',3,'💎 Tầng 3: Dịch vụ Phụ trợ Nâng cao (Back-End / High-Ticket &amp; Auxiliary Service)','tang-3-dich-vu-phu-tro-nang-cao-back-end-high-ticket-amp-auxiliary-service',50,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('42ce77b9-b442-42da-a274-d9e16564f66f','495de6a1-1b5d-4bf5-bd09-07523091fc68',73,'text','*Gia tăng giá trị trọn đời (LTV) của khách hàng và biến họ thành những người lan tỏa thương hiệu.*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('85e0457d-c0d9-43d9-8674-26a2aaf7a02c','495de6a1-1b5d-4bf5-bd09-07523091fc68',74,'text','- **Mục tiêu cốt lõi:** Khai thác sâu hơn nhu cầu phát sinh sau khi khách hàng đã giải quyết xong vấn đề cốt lõi. Duy trì vòng lặp tương tác với thương hiệu.- **Đặc điểm vận hành:**Tính cá nhân hóa (Personalization) cực kỳ cao.- Tập trung vào sự tiện lợi, nâng cấp trải nghiệm sống, bảo hành trọn đời hoặc duy trì tính bền vững (Sustainability).',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('51d63973-4f17-43dc-99c6-0efe11875e9e','495de6a1-1b5d-4bf5-bd09-07523091fc68',75,'text','- *Mô hình Dịch vụ/Phòng khám:* Gói thẻ thành viên gia đình (Family Care), dịch vụ thẩm mỹ duy trì định kỳ, các sản phẩm chăm sóc cao cấp tại nhà được cá nhân hóa theo hồ sơ bệnh án.- *Mô hình Kỹ thuật/Bán lẻ:* Gói nâng cấp linh kiện công nghệ mới, hợp đồng bảo trì hệ thống chuẩn DevOps định kỳ hàng năm, cung cấp vật tư tiêu hao độc quyền.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('0166a7aa-6f5d-4eee-a4be-8ba391724f7f','23-strategy-os','0435600e-6922-4805-a059-4551b0c39e02',3,'MA TRẬN ĐỒNG BỘ VẬN HÀNH VÀ CHUYỂN ĐỔI','ma-tran-ong-bo-van-hanh-va-chuyen-oi',51,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c257567e-45ed-477c-8864-1f75ab629445','0166a7aa-6f5d-4eee-a4be-8ba391724f7f',76,'text','Để phễu dịch vụ vận hành mượt mà, các bộ phận phải phối hợp theo ma trận tiêu chuẩn dưới đây:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('35aa09b0-2198-4a76-930e-b661acf5088e','23-strategy-os','0435600e-6922-4805-a059-4551b0c39e02',3,'NGUYÊN TẮC VÀNG TRONG ĐIỀU HÀNH PHỄU','nguyen-tac-vang-trong-ieu-hanh-pheu',52,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e5b09405-2fe5-45a6-bace-81f7a3844bcb','35aa09b0-2198-4a76-930e-b661acf5088e',77,'text','- **Không "Treo đầu dê bán thịt chó":** Dịch vụ thu hút ở Tầng 1 phải có chất lượng đồng nhất với Tầng 2. Việc dùng Tầng 1 làm mồi nhử kém chất lượng để ép khách hàng mua Tầng 2 sẽ phá hủy định vị "tử tế và minh bạch" của thương hiệu.- **Quản trị bằng dữ liệu:** Sử dụng các nhịp kiểm toán dữ liệu (D-Sync, W-Audit) để phát hiện ngay tầng nào đang bị nghẽn (Ví dụ: Khách đến Tầng 1 rất đông nhưng không chuyển sang Tầng 2 \\rightarrow rà soát ngay năng lực tư vấn chuyên gia hoặc quy trình checklist tiếp đón).',NULL,NULL,NULL,NULL,NULL);
